const configRows = $input.all();
const config = {};

for (const row of configRows) {
  const rawKey = row.json['Key'] || row.json['key'] || '';
  const rawValue = row.json['Value'] || row.json['value'] || '';
  const key = String(rawKey).trim();
  const value = String(rawValue).trim();
  if (key && value) config[key] = value;
}

// Parse competitors
config.competitors = [];
for (let i = 1; i <= 5; i++) {
  const comp = config[`competitor_${i}`];
  if (comp && String(comp).trim()) config.competitors.push(String(comp).trim());
}

// Parse seed keywords (comma-separated)
config.seed_keywords = String(config.seed_keywords || '')
  .split(',').map(k => k.trim()).filter(Boolean);

// Parse brand colors
config.brand_colors_array = String(config.brand_colors || '')
  .split(',').map(c => c.trim()).filter(Boolean);

// Numeric configs with defaults
config.max_blogs_per_run = parseInt(config.max_blogs_per_run) || 5;
config.min_keyword_volume = parseInt(config.min_keyword_volume) || 100;
config.content_length_target = parseInt(config.content_length_target) || 2000;
config.serp_results_count = parseInt(config.serp_results_count) || 10;

// Defaults
config.language = config.language || 'tr';
config.country_code = config.country_code || 'TR';
config.image_style = config.image_style || 'modern, minimalist, corporate';
config.today = new Date().toISOString().split('T')[0];

return [{ json: { config } }];

const config = $('Build Config').first().json.config;

let existingKeywords = [];
try {
  existingKeywords = $('Read Keywords Sheet').all()
    .map(r => r.json).filter(r => r.keyword);
} catch(e) {}

let pipelineItems = [];
try {
  pipelineItems = $('Read Content Pipeline').all()
    .map(r => r.json).filter(r => r.content_id);
} catch(e) {}

const resumeItems = pipelineItems.filter(row => {
  const s = row.status;
  return s && !['publish_ready', 'published', 'rejected'].includes(s);
});

const approvedUnassigned = existingKeywords.filter(
  k => (k.status === 'approved' || k.status === 'new') && !k.assigned_content_id
);
const needsDiscovery = approvedUnassigned.length === 0 && resumeItems.length === 0;

return [{
  json: {
    config,
    needsDiscovery,
    resumeCount: resumeItems.length,
    existingKeywords: existingKeywords.map(k => (k.keyword || '').toLowerCase()),
    resumeItems,
    approvedKeywords: approvedUnassigned
  }
}];

const data = $input.first().json;
const config = data.config;
const competitors = config.competitors || [];
const seedKeywords = config.seed_keywords || [];

if (seedKeywords.length === 0 && competitors.length === 0) {
  throw new Error('Config hatas: seed_keywords veya competitor_1..5 tanimlanmali!');
}

const queries = [];

// Seed keyword searches
for (const kw of seedKeywords) {
  queries.push({
    query: kw,
    type: 'seed_keyword',
    config
  });
}

// Competitor site searches - find their top content
for (const comp of competitors) {
  queries.push({
    query: `site:${comp}`,
    type: 'competitor_content',
    competitor: comp,
    config
  });
}

// Competitor + seed keyword combinations
for (const comp of competitors.slice(0, 3)) {
  for (const kw of seedKeywords.slice(0, 3)) {
    queries.push({
      query: `site:${comp} ${kw}`,
      type: 'competitor_keyword',
      competitor: comp,
      keyword: kw,
      config
    });
  }
}

return queries.map(q => ({ json: q }));

const searchItem = $('Process Searches').first().json;
const serpData = $json;

// Extract organic results
const organicResults = (serpData.organic_results || []).map(r => ({
  position: r.position,
  title: r.title || '',
  link: r.link || '',
  snippet: r.snippet || '',
  displayed_link: r.displayed_link || '',
}));

// Extract related searches
const relatedSearches = (serpData.related_searches || []).map(r => r.query || '');

// Extract people also ask
const peopleAlsoAsk = (serpData.related_questions || []).map(r => ({
  question: r.question || '',
  snippet: r.snippet || '',
}));

// Search information
const searchInfo = {
  total_results: serpData.search_information?.total_results || 0,
  query_displayed: serpData.search_information?.query_displayed || searchItem.query,
};

return [{
  json: {
    query: searchItem.query,
    type: searchItem.type,
    competitor: searchItem.competitor || '',
    keyword: searchItem.keyword || '',
    config: searchItem.config,
    serp: {
      organic: organicResults,
      related_searches: relatedSearches,
      people_also_ask: peopleAlsoAsk,
      search_info: searchInfo,
    }
  }
}];

// Merge all SERP results into a comprehensive dataset
const allItems = $input.all();
let config = null;

const allOrganicResults = [];
const allRelatedSearches = new Set();
const allPeopleAlsoAsk = [];
const competitorPages = {};

for (const item of allItems) {
  const d = item.json;
  if (!config && d.config) config = d.config;

  // Collect organic results
  for (const r of (d.serp?.organic || [])) {
    allOrganicResults.push({
      ...r,
      query: d.query,
      search_type: d.type,
      competitor: d.competitor,
    });
  }

  // Collect related searches
  for (const rs of (d.serp?.related_searches || [])) {
    allRelatedSearches.add(rs.toLowerCase().trim());
  }

  // Collect people also ask
  for (const paa of (d.serp?.people_also_ask || [])) {
    allPeopleAlsoAsk.push(paa);
  }

  // Collect competitor pages
  if (d.type === 'competitor_content' || d.type === 'competitor_keyword') {
    const comp = d.competitor;
    if (!competitorPages[comp]) competitorPages[comp] = [];
    for (const r of (d.serp?.organic || [])) {
      competitorPages[comp].push({
        url: r.link,
        title: r.title,
        snippet: r.snippet,
        position: r.position,
      });
    }
  }
}

return [{
  json: {
    config,
    serpSummary: {
      totalOrganicResults: allOrganicResults.length,
      uniqueRelatedSearches: Array.from(allRelatedSearches),
      peopleAlsoAsk: allPeopleAlsoAsk.slice(0, 20),
      competitorPages,
      topResults: allOrganicResults.slice(0, 50),
    }
  }
}];

const data = $input.first().json;
const config = data.config;
const serp = data.serpSummary;

// Format SERP data for Gemini analysis
const competitorSummary = Object.entries(serp.competitorPages)
  .map(([comp, pages]) => {
    const pageList = pages.slice(0, 10).map(p =>
      `  - [${p.position}] "${p.title}" - ${p.snippet?.substring(0, 100) || ''}`
    ).join('\n');
    return `Rakip: ${comp}\n${pageList}`;
  }).join('\n\n');

const topResultsList = serp.topResults.slice(0, 30).map(r =>
  `- [${r.position}] (${r.search_type}) "${r.title}" | ${r.displayed_link} | ${r.snippet?.substring(0, 80) || ''}`
).join('\n');

const relatedList = serp.uniqueRelatedSearches.slice(0, 30).join(', ');
const paaList = serp.peopleAlsoAsk.slice(0, 15).map(p => `- ${p.question}`).join('\n');

const prompt = `Sen bir SEO uzmani ve anahtar kelime analistsin. Google arama sonuclarini analiz ederek hedef siteye uygun anahtar kelimeleri ve blog konularini belirle.

