const resp = $json;
const config = $('Build KW Analysis Prompt').first().json.config;

let keywords;
try {
  const text = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  keywords = JSON.parse(clean.match(/\[[\s\S]*\]/)[0]);
} catch(e) {
  throw new Error('Gemini KW analysis parse error: ' + e.message);
}

return keywords.map(kw => ({
  json: {
    keyword: kw.keyword || '',
    source: 'serp_analysis',
    source_detail: 'SerpAPI + Gemini',
    estimated_volume: kw.estimated_volume || 'orta',
    competition: kw.competition || 'orta',
    intent: kw.intent || 'informational',
    is_content_gap: kw.is_content_gap ? 'TRUE' : 'FALSE',
    priority_score: kw.priority_score || 50,
    related_keywords: (kw.related_keywords || []).join(', '),
    suggested_title: kw.suggested_title_tr || '',
    content_angle: kw.content_angle || '',
    paa_questions: (kw.paa_questions || []).join(' | '),
    cluster_name: '',
    status: 'new',
    assigned_content_id: '',
    discovery_date: new Date().toISOString()
